import{_ as d}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as t,c as s,a as e,b as a,e as l,d as r}from"./app-802747a1.js";const u={},v=e("h1",{id:"ubuntu安装java",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#ubuntu安装java","aria-hidden":"true"},"#"),a(" ubuntu安装java")],-1),c=e("hr",null,null,-1),o={href:"https://zhuanlan.zhihu.com/p/137114682",target:"_blank",rel:"noopener noreferrer"},p=e("li",null,"2023-06-01 01:26:14",-1),m=r(`<hr><p>在这个指南中，我们将会描述如何在 Ubuntu 20.04 上安装 Java。</p><p>Java 是世界上最流行的编程语言之一，被用来构建各种不同的应用和系统。Java 运行在所有的主流操作系统和设备上。你可以在你的笔记本，电话和游戏中发现使用 Java 开发的应用。</p><h2 id="一、开始之前" tabindex="-1"><a class="header-anchor" href="#一、开始之前" aria-hidden="true">#</a> 一、开始之前</h2><p>有很多不同的 Java 实现。OpenJDK 和 Oracle Java 是最主要的两个 Java 实现，除了 Oracle Java 拥有极少的一些额外特性之外，它们两个基本没有什么不同。 Oracle Java 授权仅仅允许作为非商业软件的使用，例如：个人用途和开发用途。</p><p>默认的 Ubuntu 20.04 源仓库包含了两个 OpenJDK 软件包，, Java Runtime Environment (JRE) 和 Java Development Kit (JDK)。JRE 主要包含了 Java 虚拟机（JVM），类和允许你运行 Java 程序的二进制包。 JDK 包含 JRE 和用于构建 Java 应用的开发/调试工具和库文件。</p><p>如果你不确定要安装哪一个版本的 Java，我们通常推荐安装 OpenJDK (JDK 11)版本。一些基于 Java 的应用可能需要运行在指定的 Java 版本下，你应该查阅应用文档。</p><h2 id="二、安装-openjdk-11" tabindex="-1"><a class="header-anchor" href="#二、安装-openjdk-11" aria-hidden="true">#</a> 二、安装 OpenJDK 11</h2><p>在写作的时候，Java 11 是 Java 的一个长期支持版本（LTS）。它同时也是 Ubuntu 20.04的默认 Java 开发和运行环境。</p><p>以 root 或者其他 sudo 权限用户身份 运行下面的命令，更新软件包索引，并且安装OpenJDK 11 JDK 软件包：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sudo apt update
sudo apt install openjdk-11-jdk
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>一旦安装完成，你可以通过检查 Java 版本来验证它：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>java -version
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>输出类似下面这样：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>openjdk version &quot;11.0.7&quot; 2020-04-14
OpenJDK Runtime Environment (build 11.0.7+10-post-Ubuntu-3ubuntu1)
OpenJDK 64-Bit Server VM (build 11.0.7+10-post-Ubuntu-3ubuntu1, mixed mode, sharing)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>就这些！此时，你已经成功地在你的 Ubuntu 系统上安装好了 Java。</p><p>JRE 被包含在 JDK 软件包中。如果你仅仅需要 JRE，安装<code>openjdk-11-jre</code>​软件包。最小 Java 运行环境，安装<code>openjdk-11-jdk-headless</code>​软件包。</p><h2 id="三、安装-openjdk-8" tabindex="-1"><a class="header-anchor" href="#三、安装-openjdk-8" aria-hidden="true">#</a> 三、安装 OpenJDK 8</h2><p>Java 8，前一个 Java LTS 版本，目前仍被广泛应用。如果你的应用运行在 Java 8 上，你可以通过输入下面的命令，安装它：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sudo apt update
sudo apt install openjdk-8-jdk
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>通过检查 Java 版本，来验证安装过程：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>java -version
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>输出将会像下面这样：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>openjdk version &quot;1.8.0_252&quot;
OpenJDK Runtime Environment (build 1.8.0_252-8u252-b09-1ubuntu1-b09)
OpenJDK 64-Bit Server VM (build 25.252-b09, mixed mode)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="四、设置默认版本" tabindex="-1"><a class="header-anchor" href="#四、设置默认版本" aria-hidden="true">#</a> 四、设置默认版本</h2><p>如果你在你的 Ubuntu 系统上安装了多个 Java 版本，你可以输入下面的命令，检测哪个版本被设置成了默认值：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>java -version
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>想要修改默认的版本，使用<code>update-alternatives</code>​命令：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sudo update-alternatives --config java
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>输出像下面这样：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>There are 2 choices for the alternative java (providing /usr/bin/java).

  Selection    Path                                            Priority   Status
------------------------------------------------------------
* 0            /usr/lib/jvm/java-11-openjdk-amd64/bin/java      1111      auto mode
  1            /usr/lib/jvm/java-11-openjdk-amd64/bin/java      1111      manual mode
  2            /usr/lib/jvm/java-8-openjdk-amd64/jre/bin/java   1081      manual mode

Press &lt;enter&gt; to keep the current choice[*], or type selection number:
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>所有已经安装的 Java 版本将会列出来。输入你想要设置为默认值的序号，并且按&quot;Enter”。</p><h2 id="五、java-home-环境变量" tabindex="-1"><a class="header-anchor" href="#五、java-home-环境变量" aria-hidden="true">#</a> 五、JAVA_HOME 环境变量</h2><p>在一些 Java 应用中，环境变量<code>JAVA_HOME</code>​被用来表示 Java 安装位置。</p><p>想要设置 <code>JAVA_HOME</code>​ 变量，首先使用<code>update-alternatives</code>​找到 Java 安装路径:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sudo update-alternatives --config java
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在这个例子中，安装路径如下：</p><ul><li>OpenJDK 11 is located at <code>/usr/lib/jvm/java-11-openjdk-amd64/bin/java</code>​</li><li>OpenJDK 8 is located at <code>/usr/lib/jvm/java-8-openjdk-amd64/jre/bin/java</code>​</li></ul><p>一旦你发现你偏好的 Java 安装路径，打开<code>/etc/environment</code>​文件：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sudo nano /etc/environment
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>假设你想设置 <code>JAVA_HOME</code>​ 指定到 OpenJDK 11，在文件的末尾，添加下面的行：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>JAVA_HOME=&quot;/usr/lib/jvm/java-11-openjdk-amd64&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>想要让修改在当前 shell 生效，你可以登出系统，再登入系统，或者运行下面的命令：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>source /etc/environment
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>验证 <code>JAVA_HOME</code>​ 环境变量被正确设置：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo $JAVA_HOME
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>你应该可以看到 Java 安装路径：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>/usr/lib/jvm/java-11-openjdk-amd64
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>你可以使用 apt 卸载 Java，就像卸载任何软件包一样。</p><p>例如，想要卸载<code>default-jdk</code>​软件包，输入：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>sudo apt remove openjdk-11-jdk
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="七、总结" tabindex="-1"><a class="header-anchor" href="#七、总结" aria-hidden="true">#</a> 七、总结</h2><p>OpenJDK 11 和 OpenJDK 8 都在默认的 Ubuntu 20.04 软件源仓库中，并且可以使用<code>apt</code>​软件包管理工具进行安装。</p><p>​​</p><p>​​</p>`,55);function b(h,x){const n=i("ExternalLinkIcon");return t(),s("div",null,[v,c,e("ul",null,[e("li",null,[e("a",o,[a("https://zhuanlan.zhihu.com/p/137114682 - 知乎专栏"),l(n)])]),p]),m])}const j=d(u,[["render",b],["__file","ubuntu-java.html.vue"]]);export{j as default};
